package main

import (
	"fmt"
	"sync"
)

type BankAccount struct {
	balance int
	mu      sync.Mutex
}

func (ba *BankAccount) Deposit(amount int) {
	ba.mu.Lock()
	defer ba.mu.Unlock()
	ba.balance += amount
}

func (ba *BankAccount) Withdraw(amount int) bool {
	ba.mu.Lock()
	defer ba.mu.Unlock()
	if ba.balance >= amount {
		ba.balance -= amount
		return true
	}
	return false
}

func (ba *BankAccount) Balance() int {
	ba.mu.Lock()
	defer ba.mu.Unlock()
	return ba.balance
}

func main() {
	account := &BankAccount{balance: 100}
	var wg sync.WaitGroup

	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			if account.Withdraw(1) {
				account.Deposit(1)
			}
		}()
	}

	wg.Wait()
	fmt.Println("Final balance:", account.Balance())
}